+++ b/packages/coding-agent/test/interactive-tool-concurrency.test.ts
@@ -0,0 +1,216 @@
+import { existsSync, mkdirSync, rmSync } from "node:fs";
+import { tmpdir } from "node:os";
+import { join } from "node:path";
+import { Agent } from "@mariozechner/pi-agent-core";
+import { type AssistantMessage, type AssistantMessageEvent, EventStream, getModel } from "@mariozechner/pi-ai";
+import { Type } from "@sinclair/typebox";
+import { afterEach, beforeEach, describe, expect, it } from "vitest";
+import { AgentSession } from "../src/core/agent-session.js";
+import { AuthStorage } from "../src/core/auth-storage.js";
+import { ModelRegistry } from "../src/core/model-registry.js";
+import { SessionManager } from "../src/core/session-manager.js";
+import { SettingsManager } from "../src/core/settings-manager.js";
+
+class MockAssistantStream extends EventStream<AssistantMessageEvent, AssistantMessage> {
+	constructor() {
+		super(
+			(event) => event.type === "done" || event.type === "error",
+			(event) => {
+				if (event.type === "done") return event.message;
+				if (event.type === "error") return event.error;
+				throw new Error("Unexpected event type");
+			},
+		);
+	}
+}
+
+function createAssistantMessage(content: AssistantMessage["content"], stopReason: AssistantMessage["stopReason"]): AssistantMessage {
+	return {
+		role: "assistant",
+		content,
+		api: "anthropic-messages",
+		provider: "anthropic",
+		model: "mock",
+		usage: {
+			input: 0,
+			output: 0,
+			cacheRead: 0,
+			cacheWrite: 0,
+			totalTokens: 0,
+			cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0, total: 0 },
+		},
+		stopReason,
+		timestamp: Date.now(),
+	};
+}
+
+describe("interactive tool concurrency", () => {
+	let session: AgentSession;
+	let tempDir: string;
+
+	beforeEach(() => {
+		tempDir = join(tmpdir(), `pi-interactive-tool-concurrency-${Date.now()}`);
+		mkdirSync(tempDir, { recursive: true });
+	});
+
+	afterEach(() => {
+		if (session) {
+			session.dispose();
+		}
+		if (tempDir && existsSync(tempDir)) {
+			rmSync(tempDir, { recursive: true, force: true });
+		}
+	});
+
+	it("should finish a turn with two interactive tools in one assistant response", async () => {
+		const model = getModel("anthropic", "claude-sonnet-4-5")!;
+		let callCount = 0;
+
+		const askTool = (name: "ask_a" | "ask_b") => ({
+			name,
+			label: name,
+			description: name,
+			parameters: Type.Object({}),
+			async execute(_toolCallId, _params, _signal, _onUpdate, ctx) {
+				const answer = await ctx.ui.input(name, "answer");
+				return {
+					content: [{ type: "text", text: `${name}:${answer ?? "none"}` }],
+					details: {},
+				};
+			},
+		});
+
+		const agent = new Agent({
+			getApiKey: () => "test-key",
+			initialState: {
+				model,
+				systemPrompt: "Test",
+				tools: [],
+			},
+			streamFn: async (_model, context) => {
+				const stream = new MockAssistantStream();
+				queueMicrotask(() => {
+					const toolResultCount = context.messages.filter((message) => message.role === "toolResult").length;
+					if (toolResultCount >= 2) {
+						const done = createAssistantMessage([{ type: "text", text: "done" }], "stop");
+						stream.push({ type: "start", partial: { ...done, content: [] } });
+						stream.push({ type: "done", reason: "stop", message: done });
+						return;
+					}
+
+					if (callCount === 0) {
+						const withTools = createAssistantMessage(
+							[
+								{ type: "toolCall", id: "toolu_a", name: "ask_a", arguments: {} },
+								{ type: "toolCall", id: "toolu_b", name: "ask_b", arguments: {} },
+							],
+							"toolUse",
+						);
+						stream.push({ type: "start", partial: { ...withTools, content: [] } });
+						stream.push({ type: "done", reason: "toolUse", message: withTools });
+						callCount++;
+						return;
+					}
+				});
+				return stream;
+			},
+		});
+
+		const sessionManager = SessionManager.inMemory();
+		const settingsManager = SettingsManager.create(tempDir, tempDir);
+		const authStorage = AuthStorage.create(join(tempDir, "auth.json"));
+		const modelRegistry = new ModelRegistry(authStorage, tempDir);
+		authStorage.setRuntimeApiKey("anthropic", "test-key");
+
+		session = new AgentSession({
+			agent,
+			sessionManager,
+			settingsManager,
+			cwd: tempDir,
+			modelRegistry,
+			resourceLoader: {
+				getExtensions: () => ({
+					extensions: [],
+					errors: [],
+					runtime: {
+						flagValues: new Map(),
+						pendingProviderRegistrations: [],
+						registerProvider: () => {},
+						unregisterProvider: () => {},
+						sendMessage: () => {},
+						sendUserMessage: () => {},
+						appendEntry: () => {},
+						setSessionName: () => {},
+						getSessionName: () => undefined,
+						setLabel: () => {},
+						getActiveTools: () => [],
+						getAllTools: () => [],
+						setActiveTools: () => {},
+						refreshTools: () => {},
+						getCommands: () => [],
+						setModel: async () => false,
+						getThinkingLevel: () => "off",
+						setThinkingLevel: () => {},
+					},
+				}),
+				getSkills: () => ({ skills: [], diagnostics: [] }),
+				getPrompts: () => ({ prompts: [], diagnostics: [] }),
+				getThemes: () => ({ themes: [], diagnostics: [] }),
+				getAgentsFiles: () => ({ agentsFiles: [] }),
+				getSystemPrompt: () => undefined,
+				getAppendSystemPrompt: () => [],
+				extendResources: () => {},
+				reload: async () => {},
+			},
+			customTools: [askTool("ask_a"), askTool("ask_b")],
+		});
+
+		let activeInputResolve: ((value: string | undefined) => void) | undefined;
+		const uiContext = {
+			select: async () => undefined,
+			confirm: async () => false,
+			input: async () => {
+				return await new Promise<string | undefined>((resolve) => {
+					// Intentionally mimic current single-slot dialog behavior:
+					// a second call overwrites the first resolver.
+					activeInputResolve = resolve;
+				});
+			},
+			notify: () => {},
+			onTerminalInput: () => () => {},
+			setStatus: () => {},
+			setWorkingMessage: () => {},
+			setWidget: () => {},
+			setFooter: () => {},
+			setHeader: () => {},
+			setTitle: () => {},
+			custom: async () => undefined as never,
+			pasteToEditor: () => {},
+			setEditorText: () => {},
+			getEditorText: () => "",
+			editor: async () => undefined,
+			setEditorComponent: () => {},
+			get theme() {
+				throw new Error("not used");
+			},
+			getAllThemes: () => [],
+			getTheme: () => undefined,
+			setTheme: () => ({ success: false, error: "not used" }),
+			getToolsExpanded: () => false,
+			setToolsExpanded: () => {},
+		};
+
+		await session.bindExtensions({ uiContext });
+
+		const promptPromise = session.prompt("run both interactive tools");
+		await new Promise((resolve) => setTimeout(resolve, 20));
+		activeInputResolve?.("ok");
+
+		const outcome = await Promise.race([
+			promptPromise.then(() => "done" as const),
+			new Promise<"timeout">((resolve) => setTimeout(() => resolve("timeout"), 200)),
+		]);
+
+		expect(outcome).toBe("done");
+	});
+});

