+			streamFn: async (_model, context) => {
+				const stream = new MockAssistantStream();
+				queueMicrotask(() => {
+					const toolResultCount = context.messages.filter((message) => message.role === "toolResult").length;
+					if (toolResultCount >= 2) {
+						const done = createAssistantMessage([{ type: "text", text: "done" }], "stop");
+						stream.push({ type: "start", partial: { ...done, content: [] } });
+						stream.push({ type: "done", reason: "stop", message: done });
+						return;
+					}
+
+					if (callCount === 0) {
+						const withTools = createAssistantMessage(
+							[
+								{ type: "toolCall", id: "toolu_a", name: "ask_a", arguments: {} },
+								{ type: "toolCall", id: "toolu_b", name: "ask_b", arguments: {} },
+							],
+							"toolUse",
+						);
+						stream.push({ type: "start", partial: { ...withTools, content: [] } });
+						stream.push({ type: "done", reason: "toolUse", message: withTools });
+						callCount++;
+						return;
+					}
+				});
+				return stream;
+			},
+		});
+
+		const sessionManager = SessionManager.inMemory();
