+		authStorage.setRuntimeApiKey("anthropic", "test-key");
+
+		session = new AgentSession({
+			agent,
+			sessionManager,
+			settingsManager,
+			cwd: tempDir,
+			modelRegistry,
+			resourceLoader: {
+				getExtensions: () => ({
+					extensions: [],
+					errors: [],
+					runtime: {
+						flagValues: new Map(),
+						pendingProviderRegistrations: [],
+						registerProvider: () => {},
+						unregisterProvider: () => {},
+						sendMessage: () => {},
+						sendUserMessage: () => {},
+						appendEntry: () => {},
+						setSessionName: () => {},
+						getSessionName: () => undefined,
+						setLabel: () => {},
+						getActiveTools: () => [],
+						getAllTools: () => [],
+						setActiveTools: () => {},
+						refreshTools: () => {},
+						getCommands: () => [],
+						setModel: async () => false,
+						getThinkingLevel: () => "off",
+						setThinkingLevel: () => {},
+					},
+				}),
+				getSkills: () => ({ skills: [], diagnostics: [] }),
+				getPrompts: () => ({ prompts: [], diagnostics: [] }),
+				getThemes: () => ({ themes: [], diagnostics: [] }),
+				getAgentsFiles: () => ({ agentsFiles: [] }),
+				getSystemPrompt: () => undefined,
+				getAppendSystemPrompt: () => [],
+				extendResources: () => {},
+				reload: async () => {},
+			},
+			customTools: [askTool("ask_a"), askTool("ask_b")],
+		});
+
+		let activeInputResolve: ((value: string | undefined) => void) | undefined;
+		const uiContext: ExtensionUIContext = {
+			select: async () => undefined,
+			confirm: async () => false,
+			input: async () => {
+				return await new Promise<string | undefined>((resolve) => {
+					// Intentionally mimic current single-slot dialog behavior:
+					// a second call overwrites the first resolver.
+					activeInputResolve = resolve;
+				});
+			},
+			notify: () => {},
+			onTerminalInput: () => () => {},
+			setStatus: () => {},
+			setWorkingMessage: () => {},
+			setWidget: () => {},
+			setFooter: () => {},
+			setHeader: () => {},
+			setTitle: () => {},
+			custom: async () => undefined as never,
+			pasteToEditor: () => {},
+			setEditorText: () => {},
+			getEditorText: () => "",
+			editor: async () => undefined,
+			setEditorComponent: () => {},
+			get theme() {
+				return theme;
+			},
+			getAllThemes: () => [],
+			getTheme: () => undefined,
+			setTheme: () => ({ success: false, error: "not used" }),
+			getToolsExpanded: () => false,
+			setToolsExpanded: () => {},
+		};
+
+		await session.bindExtensions({ uiContext });
+
+		const promptPromise = session.prompt("run both interactive tools");
+		await new Promise((resolve) => setTimeout(resolve, 20));
+		activeInputResolve?.("ok");
+
+		const outcome = await Promise.race([
+			promptPromise.then(() => "done" as const),
+			new Promise<"timeout">((resolve) => setTimeout(() => resolve("timeout"), 200)),
+		]);
+
+		expect(outcome).toBe("done");
+	});
+});

